// MARK: - WebView Message Handler Names
enum MessageHandlerName: String, CaseIterable {
    case camera = "cameraHandler"
    case pushNotification = "pushNotificationHandler"
    case inAppPurchase = "inAppPurchaseHandler"
    case nativeLog = "nativeLogHandler"
    case shareContent = "shareContentHandler"
    case hapticFeedback = "hapticFeedbackHandler"
}

// MARK: - Native Bridge Protocol
protocol NativeBridgeDelegate: AnyObject {
    func didReceiveCameraRequest(options: [String: Any])
    func didReceivePushNotificationRequest(action: String, options: [String: Any])
    func didReceiveInAppPurchaseRequest(action: String, productId: String?)
    func didReceiveShareRequest(content: [String: Any])
}

