    // MARK: - Native Bridge JavaScript
    private func createNativeBridgeScript() -> String {
        return """
        (function() {
            'use strict';

            // Callback storage
            window._nativeBridgeCallbacks = {};
            var callbackId = 0;

            function generateCallbackId() {
                return 'cb_' + (++callbackId) + '_' + Date.now();
            }

            function sendMessage(handlerName, data, callback) {
                var message = data || {};
                if (callback) {
                    var cbId = generateCallbackId();
                    window._nativeBridgeCallbacks[cbId] = callback;
                    message._callbackId = cbId;
                }
                window.webkit.messageHandlers[handlerName].postMessage(message);
            }

            // Native Bridge API
            window.NativeBridge = {
                // Platform detection
                isNativeApp: true,
                platform: 'iOS',
                appVersion: '\(Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0.0")',

                // Camera
                camera: {
                    open: function(options, callback) {
                        sendMessage('cameraHandler', {
                            action: 'open',
                            options: options || {}
                        }, callback);
                    },
                    checkPermission: function(callback) {
                        sendMessage('cameraHandler', {
                            action: 'checkPermission'
                        }, callback);
                    },
                    requestPermission: function(callback) {
                        sendMessage('cameraHandler', {
                            action: 'requestPermission'
                        }, callback);
                    }
                },

                // Push Notifications
                pushNotifications: {
                    register: function(callback) {
                        sendMessage('pushNotificationHandler', {
                            action: 'register'
                        }, callback);
                    },
                    getToken: function(callback) {
                        sendMessage('pushNotificationHandler', {
                            action: 'getToken'
                        }, callback);
                    },
                    checkPermission: function(callback) {
                        sendMessage('pushNotificationHandler', {
                            action: 'checkPermission'
                        }, callback);
                    },
                    requestPermission: function(callback) {
                        sendMessage('pushNotificationHandler', {
                            action: 'requestPermission'
                        }, callback);
                    },
                    setBadge: function(count) {
                        sendMessage('pushNotificationHandler', {
                            action: 'setBadge',
                            count: count
                        });
                    }
                },

                // In-App Purchases
                inAppPurchase: {
                    getProducts: function(productIds, callback) {
                        sendMessage('inAppPurchaseHandler', {
                            action: 'getProducts',
                            productIds: productIds
                        }, callback);
                    },
                    purchase: function(productId, callback) {
                        sendMessage('inAppPurchaseHandler', {
                            action: 'purchase',
                            productId: productId
                        }, callback);
                    },
                    restorePurchases: function(callback) {
                        sendMessage('inAppPurchaseHandler', {
                            action: 'restore'
                        }, callback);
                    }
                },

                // Share
                share: function(content, callback) {
                    sendMessage('shareContentHandler', content, callback);
                },

                // Haptic Feedback
                haptic: function(type) {
                    sendMessage('hapticFeedbackHandler', { type: type || 'medium' });
                },

                // Native logging
                log: function(message, level) {
                    sendMessage('nativeLogHandler', {
                        message: message,
                        level: level || 'info'
                    });
                },

                // Resolve callback from native
                _resolveCallback: function(callbackId, data) {
                    var callback = window._nativeBridgeCallbacks[callbackId];
                    if (callback) {
                        callback(data);
                        delete window._nativeBridgeCallbacks[callbackId];
                    }
                }
            };

            // Dispatch event to notify web app that bridge is ready
            var event = new CustomEvent('NativeBridgeReady', { detail: { platform: 'iOS' } });
            document.dispatchEvent(event);

            console.log('[NativeBridge] iOS bridge initialized');
        })();
        """
    }

    // MARK: - Custom User Agent
    private func buildCustomUserAgent() -> String {
        let appName = Bundle.main.infoDictionary?["CFBundleName"] as? String ?? "HybridApp"
        let appVersion = Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0.0"
        let buildNumber = Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "1"
        return "Mozilla/5.0 (iPhone; CPU iPhone OS \(UIDevice.current.systemVersion.replacingOccurrences(of: ".", with: "_")) like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) \(appName)/\(appVersion).\(buildNumber) Mobile/15E148 NativeApp/iOS"
    }

    // MARK: - JavaScript Execution Helpers
    func evaluateJavaScript(_ script: String, completion: ((Any?, Error?) -> Void)? = nil) {
        DispatchQueue.main.async { [weak self] in
            self?.webView.evaluateJavaScript(script) { result, error in
                if let error = error {
                    print("[WebView] JS Error: \(error.localizedDescription)")
