        }
    }

    func sendCallbackToWeb(callbackId: String, data: [String: Any]) {
        guard let jsonData = try? JSONSerialization.data(withJSONObject: data),
              let jsonString = String(data: jsonData, encoding: .utf8) else { return }
        let script = "window.NativeBridge._resolveCallback('\(callbackId)', \(jsonString));"
        evaluateJavaScript(script)
    }

    func sendEventToWeb(eventName: String, data: [String: Any]) {
        guard let jsonData = try? JSONSerialization.data(withJSONObject: data),
              let jsonString = String(data: jsonData, encoding: .utf8) else { return }
        let script = """
        (function() {
            var event = new CustomEvent('\(eventName)', { detail: \(jsonString) });
            document.dispatchEvent(event);
        })();
        """
        evaluateJavaScript(script)
    }

