// MARK: - WKScriptMessageHandler
extension HybridWebViewController: WKScriptMessageHandler {

    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let handlerName = MessageHandlerName(rawValue: message.name) else {
            print("[NativeBridge] Unknown handler: \(message.name)")
            return
        }

        let body = message.body as? [String: Any] ?? [:]
        let callbackId = body["_callbackId"] as? String

        print("[NativeBridge] Received message - Handler: \(handlerName.rawValue), Body: \(body)")

        switch handlerName {
        case .camera:
            handleCameraMessage(body: body, callbackId: callbackId)
        case .pushNotification:
            handlePushNotificationMessage(body: body, callbackId: callbackId)
        case .inAppPurchase:
            handleInAppPurchaseMessage(body: body, callbackId: callbackId)
        case .nativeLog:
            handleNativeLog(body: body)
        case .shareContent:
            handleShareContent(body: body, callbackId: callbackId)
        case .hapticFeedback:
            handleHapticFeedback(body: body)
        }
    }

    // MARK: - Camera Handler
    private func handleCameraMessage(body: [String: Any], callbackId: String?) {
        let action = body["action"] as? String ?? ""
        let options = body["options"] as? [String: Any] ?? [:]

        switch action {
        case "checkPermission":
            let status = AVCaptureDevice.authorizationStatus(for: .video)
            let statusString: String
            switch status {
            case .authorized: statusString = "authorized"
            case .denied: statusString = "denied"
            case .restricted: statusString = "restricted"
            case .notDetermined: statusString = "notDetermined"
            @unknown default: statusString = "unknown"
            }
            if let cbId = callbackId {
                sendCallbackToWeb(callbackId: cbId, data: ["status": statusString])
            }

        case "requestPermission":
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                if let cbId = callbackId {
                    self?.sendCallbackToWeb(callbackId: cbId, data: [
                        "granted": granted,
                        "status": granted ? "authorized" : "denied"
                    ])
                }
            }

        case "open":
            openCamera(options: options, callbackId: callbackId)

        default:
            print("[NativeBridge] Unknown camera action: \(action)")
        }

        bridgeDelegate?.didReceiveCameraRequest(options: options)
    }

    private func openCamera(options: [String: Any], callbackId: String?) {
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }

            let status = AVCaptureDevice.authorizationStatus(for: .video)
            guard status == .authorized else {
                if status == .notDetermined {
                    AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                        if granted {
                            self?.openCamera(options: options, callbackId: callbackId)
                        } else if let cbId = callbackId {
                            self?.sendCallbackToWeb(callbackId: cbId, data: [
                                "error": "Camera permission denied",
                                "success": false
                            ])
                        }
                    }
                } else if let cbId = callbackId {
                    self.sendCallbackToWeb(callbackId: cbId, data: [
                        "error": "Camera permission denied",
                        "success": false
                    ])
                }
                return
            }

            guard UIImagePickerController.isSourceTypeAvailable(.camera) else {
                if let cbId = callbackId {
                    self.sendCallbackToWeb(callbackId: cbId, data: [
                        "error": "Camera not available",
                        "success": false
                    ])
                }
                return
            }

            let picker = UIImagePickerController()
            picker.sourceType = .camera
            picker.delegate = self
            picker.allowsEditing = options["allowsEditing"] as? Bool ?? false

            let mediaType = options["mediaType"] as? String ?? "photo"
            if mediaType == "video" {
                picker.mediaTypes = ["public.movie"]
                picker.videoMaximumDuration = options["maxDuration"] as? TimeInterval ?? 60
            }

            if let cameraDevice = options["cameraDevice"] as? String, cameraDevice == "front" {
                picker.cameraDevice = .front
            }

            // Store callback ID for later use
            objc_setAssociatedObject(picker, "callbackId", callbackId, .OBJC_ASSOCIATION_RETAIN)

            self.present(picker, animated: true)
        }
    }

    // MARK: - Push Notification Handler
    private func handlePushNotificationMessage(body: [String: Any], callbackId: String?) {
        let action = body["action"] as? String ?? ""

        switch action {
        case "register":
            DispatchQueue.main.async {
                UIApplication.shared.registerForRemoteNotifications()
            }
            if let cbId = callbackId {
                sendCallbackToWeb(callbackId: cbId, data: ["success": true, "message": "Registration initiated"])
            }

        case "requestPermission":
            UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
                var result: [String: Any] = ["granted": granted]
                if let error = error {
                    result["error"] = error.localizedDescription
                }
                if granted {
                    DispatchQueue.main.async {
                        UIApplication.shared.registerForRemoteNotifications()
                    }
                }
                if let cbId = callbackId {
                    self?.sendCallbackToWeb(callbackId: cbId, data: result)
                }
            }

        case "checkPermission":
            UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
                let statusString: String
                switch settings.authorizationStatus {
                case .authorized: statusString = "authorized"
                case .denied: statusString = "denied"
                case .notDetermined: statusString = "notDetermined"
                case .provisional: statusString = "provisional"
                case .ephemeral: statusString = "ephemeral"
                @unknown default: statusString = "unknown"
                }
                if let cbId = callbackId {
                    self?.sendCallbackToWeb(callbackId: cbId, data: [
                        "status": statusString,
                        "alertEnabled": settings.alertSetting == .enabled,
                        "badgeEnabled": settings.badgeSetting == .enabled,
                        "soundEnabled": settings.soundSetting == .enabled
                    ])
                }
            }

        case "getToken":
            // Token is typically stored in UserDefaults after registration
            let token = UserDefaults.standard.string(forKey: "devicePushToken") ?? ""
            if let cbId = callbackId {
                sendCallbackToWeb(callbackId: cbId, data: [
                    "token": token,
                    "hasToken": !token.isEmpty
                ])
            }

        case "setBadge":
            let count = body["count"] as? Int ?? 0
            DispatchQueue.main.async {
                UIApplication.shared.applicationIconBadgeNumber = count
            }

        default:
            print("[NativeBridge] Unknown push notification action: \(action)")
        }

        bridgeDelegate?.didReceivePushNotificationRequest(action: action, options: body)
    }

    // MARK: - In-App Purchase Handler
    private func handleInAppPurchaseMessage(body: [String: Any], callbackId: String?) {
        let action = body["action"] as? String ?? ""
        let productId = body["productId"] as? String

        switch action {
        case "getProducts":
            let productIds = body["productIds"] as? [String] ?? []
            fetchProducts(productIds: productIds, callbackId: callbackId)

        case "purchase":
            guard let productId = productId else {
                if let cbId = callbackId {
                    sendCallbackToWeb(callbackId: cbId, data: [
                        "error": "Product ID is required",
                        "success": false
                    ])
                }
                return
            }
            purchaseProduct(productId: productId, callbackId: callbackId)

        case "restore":
            pendingPurchaseCallbackId = callbackId
            SKPaymentQueue.default().restoreCompletedTransactions()

        default:
            print("[NativeBridge] Unknown IAP action: \(action)")
        }

        bridgeDelegate?.didReceiveInAppPurchaseRequest(action: action, productId: productId)
    }

    private func fetchProducts(productIds: [String], callbackId: String?) {
        let request = SKProductsRequest(productIdentifiers: Set(productIds))
        request.delegate = self
        objc_setAssociatedObject(request, "callbackId", callbackId, .OBJC_ASSOCIATION_RETAIN)
        productsRequest = request
        request.start()
    }

    private func purchaseProduct(productId: String, callbackId: String?) {
        guard let product = availableProducts.first(where: { $0.productIdentifier == productId }) else {
            if let cbId = callbackId {
                sendCallbackToWeb(callbackId: cbId, data: [
                    "error": "Product not found. Fetch products first.",
                    "success": false
                ])
            }
            return
        }

        guard SKPaymentQueue.canMakePayments() else {
            if let cbId = callbackId {
                sendCallbackToWeb(callbackId: cbId, data: [
                    "error": "In-app purchases are not allowed on this device",
                    "success": false
                ])
            }
            return
        }

        pendingPurchaseCallbackId = callbackId
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }

    // MARK: - Native Log Handler
    private func handleNativeLog(body: [String: Any]) {
        let message = body["message"] as? String ?? ""
        let level = body["level"] as? String ?? "info"

        switch level {
        case "error":
            print("🔴 [WebApp] \(message)")
        case "warn":
            print("🟡 [WebApp] \(message)")
        case "debug":
            print("🔵 [WebApp] \(message)")
        default:
            print("⚪ [WebApp] \(message)")
        }
    }

    // MARK: - Share Content Handler
    private func handleShareContent(body: [String: Any], callbackId: String?) {
        DispatchQueue.main.async { [weak self] in
            var items: [Any] = []

            if let text = body["text"] as? String {
                items.append(text)
            }
            if let urlString = body["url"] as? String, let url = URL(string: urlString) {
                items.append(url)
            }
            if let title = body["title"] as? String, items.isEmpty {
                items.append(title)
            }

            guard !items.isEmpty else {
                if let cbId = callbackId {
                    self?.sendCallbackToWeb(callbackId: cbId, data: [
                        "error": "No content to share",
                        "success": false
                    ])
                }
                return
            }

            let activityVC = UIActivityViewController(activityItems: items, applicationActivities: nil)
            activityVC.completionWithItemsHandler = { [weak self] activityType, completed, _, error in
                if let cbId = callbackId {
                    self?.sendCallbackToWeb(callbackId: cbId, data: [
                        "success": completed,
                        "activityType": activityType?.rawValue ?? "",
                        "error": error?.localizedDescription ?? ""
                    ])
                }
            }

            // iPad support
            if let popover = activityVC.popoverPresentationController {
                popover.sourceView = self?.view
                popover.sourceRect = CGRect(x: self?.view.bounds.midX ?? 0,
                                           y: self?.view.bounds.midY ?? 0,
                                           width: 0, height: 0)
            }

            self?.present(activityVC, animated: true)
        }

        bridgeDelegate?.didReceiveShareRequest(content: body)
    }

    // MARK: - Haptic Feedback Handler
    private func handleHapticFeedback(body: [String: Any]) {
        let type = body["type"] as? String ?? "medium"

        DispatchQueue.main.async {
            switch type {
            case "light":
                let generator = UIImpactFeedbackGenerator(style: .light)
                generator.impactOccurred()
            case "medium":
                let generator = UIImpactFeedbackGenerator(style: .medium)
                generator.impactOccurred()
            case "heavy":
                let generator = UIImpactFeedbackGenerator(style: .heavy)
                generator.impactOccurred()
            case "success":
                let generator = UINotificationFeedbackGenerator()
                generator.notificationOccurred(.success)
            case "warning":
                let generator = UINotificationFeedbackGenerator()
                generator.notificationOccurred(.warning)
            case "error":
                let generator = UINotificationFeedbackGenerator()
                generator.notificationOccurred(.error)
            case "selection":
                let generator = UISelectionFeedbackGenerator()
                generator.selectionChanged()
            default:
                let generator = UIImpactFeedbackGenerator(style: .medium)
                generator.impactOccurred()
            }
        }
    }
}

// MARK: - WKNavigationDelegate
extension HybridWebViewController: WKNavigationDelegate {

    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }

        // Handle external links (tel:, mailto:, etc.)
        let scheme = url.scheme?.lowercased() ?? ""
        if ["tel", "mailto", "sms", "facetime"].contains(scheme) {
            UIApplication.shared.open(url, options: [:], completionHandler: nil)
            decisionHandler(.cancel)
            return
        }

        // Handle universal links or deep links
        if scheme == "itms-apps" || scheme == "itms-appss" {
            UIApplication.shared.open(url, options: [:], completionHandler: nil)
            decisionHandler(.cancel)
            return
        }

        // Allow navigation to our domain, block others or open in Safari
        if let host = url.host {
            let allowedDomains = ["your-mobile-website.com", "www.your-mobile-website.com", "api.your-mobile-website.com"]
            if !allowedDomains.contains(host) && navigationAction.navigationType == .linkActivated {
                UIApplication.shared.open(url, options: [:], completionHandler: nil)
                decisionHandler(.cancel)
                return
            }
        }

        decisionHandler(.allow)
    }

    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        removeErrorView()
        print("[WebView] Started loading: \(webView.url?.absoluteString ?? "unknown")")
    }

    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        removeErrorView()
        print("[WebView] Finished loading: \(webView.url?.absoluteString ?? "unknown")")

        // Inject any additional configuration after page load
        let deviceInfo: [String: Any] = [
            "model": UIDevice.current.model,
            "systemVersion": UIDevice.current.systemVersion,
            "appVersion": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0.0",
            "safeAreaInsets": [
                "top": view.safeAreaInsets.top,
                "bottom": view.safeAreaInsets.bottom,
                "left": view.safeAreaInsets.left,
                "right": view.safeAreaInsets.right
            ]
        ]

        if let jsonData = try? JSONSerialization.data(withJSONObject: deviceInfo),
           let jsonString = String(data: jsonData, encoding: .utf8) {
            evaluateJavaScript("window.NativeBridge.deviceInfo = \(jsonString);")
        }
    }

    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        handleWebViewError(error)
    }

    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        handleWebViewError(error)
    }

    private func handleWebViewError(_ error: Error) {
        let nsError = error as NSError

        // Ignore cancelled requests
        if nsError.code == NSURLErrorCancelled { return }

        print("[WebView] Error: \(error.localizedDescription)")

        var message = "Failed to load the page."
        if nsError.code == NSURLErrorNotConnectedToInternet {
            message = "No internet connection.\nPlease check your network settings."
        } else if nsError.code == NSURLErrorTimedOut {
            message = "The request timed out.\nPlease try again."
        }

        showErrorView(message: message)
    }

    func webView(_ webView: WKWebView, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        // Handle SSL certificate validation
        if let serverTrust = challenge.protectionSpace.serverTrust {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            completionHandler(.performDefaultHandling, nil)
        }
    }
}

// MARK: - WKUIDelegate
extension HybridWebViewController: WKUIDelegate {

    // Handle JavaScript alert()
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping () -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }

    // Handle JavaScript confirm()
    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (Bool) -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }

    // Handle JavaScript prompt()
    func webView(_ webView: WKWebView, runJavaScriptTextInputPanelWithPrompt prompt: String, defaultText: String?, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (String?) -> Void) {
        let alert = UIAlertController(title: nil, message: prompt, preferredStyle: .alert)
        alert.addTextField { textField in
            textField.text = defaultText
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(nil)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(alert.textFields?.first?.text)
        })
        present(alert, animated: true)
    }

    // Handle window.open() - open in same webview or new controller
    func webView(_ webView: WKWebView, createWebViewWith configuration: WKWebViewConfiguration, for navigationAction: WKNavigationAction, windowFeatures: WKWindowFeatures) -> WKWebView? {
        if navigationAction.targetFrame == nil || navigationAction.targetFrame?.isMainFrame == false {
            webView.load(navigationAction.request)
        }
        return nil
    }
}

// MARK: - UIImagePickerControllerDelegate
extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {

    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        let callbackId = objc_getAssociatedObject(picker, "callbackId") as? String

        picker.dismiss(animated: true) { [weak self] in
            var result: [String: Any] = ["success": true]

            if let image = info[.editedImage] as? UIImage ?? info[.originalImage] as? UIImage {
                if let imageData = image.jpegData(compressionQuality: 0.8) {
                    let base64String = imageData.base64EncodedString()
                    result["imageBase64"] = "data:image/jpeg;base64,\(base64String)"
                    result["width"] = image.size.width
                    result["height"] = image.size.height
                }
            }

            if let mediaURL = info[.mediaURL] as? URL {
                result["mediaURL"] = mediaURL.absoluteString
            }

            if let cbId = callbackId {
                self?.sendCallbackToWeb(callbackId: cbId, data: result)
            }
        }
    }

    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        let callbackId = objc_getAssociatedObject(picker, "callbackId") as? String

        picker.dismiss(animated: true) { [weak self] in
            if let cbId = callbackId {
                self?.sendCallbackToWeb(callbackId: cbId, data: [
                    "success": false,
                    "cancelled": true
                ])
            }
        }
    }
}

// MARK: - SKProductsRequestDelegate
extension HybridWebViewController: SKProductsRequestDelegate {

    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        availableProducts = response.products
        let callbackId = objc_getAssociatedObject(request, "callbackId") as? String

        let products: [[String: Any]] = response.products.map { product in
            let formatter = NumberFormatter()
            formatter.numberStyle = .currency
            formatter.locale = product.priceLocale

            return [
                "productId": product.productIdentifier,
                "title": product.localizedTitle,
                "description": product.localizedDescription,
                "price": product.price.doubleValue,
                "priceFormatted": formatter.string(from: product.price) ?? "",
                "currencyCode": product.priceLocale.currencyCode ?? ""
            ]
        }

        if let cbId = callbackId {
            sendCallbackToWeb(callbackId: cbId, data: [
                "success": true,
                "products": products,
                "invalidProductIds": response.invalidProductIdentifiers
            ])
        }
    }

    func request(_ request: SKRequest, didFailWithError error: Error) {
        let callbackId = objc_getAssociatedObject(request, "callbackId") as? String
        if let cbId = callbackId {
            sendCallbackToWeb(callbackId: cbId, data: [
                "success": false,
                "error": error.localizedDescription
            ])
        }
    }
}

// MARK: - SKPaymentTransactionObserver
extension HybridWebViewController: SKPaymentTransactionObserver {

    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                handlePurchaseSuccess(transaction)
                queue.finishTransaction(transaction)

            case .failed:
                handlePurchaseFailure(transaction)
                queue.finishTransaction(transaction)

            case .restored:
                handlePurchaseRestored(transaction)
                queue.finishTransaction(transaction)

            case .purchasing, .deferred:
                break

            @unknown default:
                break
            }
        }
    }

    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        if let cbId = pendingPurchaseCallbackId {
            sendCallbackToWeb(callbackId: cbId, data: [
                "success": true,
                "message": "Purchases restored successfully"
            ])
            pendingPurchaseCallbackId = nil
        }
    }

    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        if let cbId = pendingPurchaseCallbackId {
            sendCallbackToWeb(callbackId: cbId, data: [
                "success": false,
                "error": error.localizedDescription
            ])
            pendingPurchaseCallbackId = nil
        }
    }

    private func handlePurchaseSuccess(_ transaction: SKPaymentTransaction) {
        var result: [String: Any] = [
            "success": true,
            "productId": transaction.payment.productIdentifier,
            "transactionId": transaction.transactionIdentifier ?? "",
            "transactionDate": transaction.transactionDate?.timeIntervalSince1970 ?? 0
        ]

        // Include receipt data for server validation
        if let receiptURL = Bundle.main.appStoreReceiptURL,
           let receiptData = try? Data(contentsOf: receiptURL) {
            result["receipt"] = receiptData.base64EncodedString()
        }

        if let cbId = pendingPurchaseCallbackId {
            sendCallbackToWeb(callbackId: cbId, data: result)
            pendingPurchaseCallbackId = nil
        }

        // Also send event for any listeners
        sendEventToWeb(eventName: "iap_purchase_success", data: result)
    }

    private func handlePurchaseFailure(_ transaction: SKPaymentTransaction) {
        let errorMessage = transaction.error?.localizedDescription ?? "Purchase failed"
        let isCancelled = (transaction.error as? SKError)?.code == .paymentCancelled

        let result: [String: Any] = [
            "success": false,
            "productId": transaction.payment.productIdentifier,
            "error": errorMessage,
            "cancelled": isCancelled
        ]

        if let cbId = pendingPurchaseCallbackId {
            sendCallbackToWeb(callbackId: cbId, data: result)
            pendingPurchaseCallbackId = nil
        }
    }

    private func handlePurchaseRestored(_ transaction: SKPaymentTransaction) {
        let result: [String: Any] = [
            "success": true,
            "productId": transaction.payment.productIdentifier,
            "transactionId": transaction.transactionIdentifier ?? "",
            "originalTransactionId": transaction.original?.transactionIdentifier ?? "",
            "restored": true
        ]

        sendEventToWeb(eventName: "iap_purchase_restored", data: result)
    }
}

// MARK: - LeakAvoider (Prevent retain cycle with WKUserContentController)
class LeakAvoider: NSObject, WKScriptMessageHandler {
    weak var delegate: WKScriptMessageHandler?

    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
        super.init()
    }

    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

// MARK: - AppDelegate Extension for Push Token
extension AppDelegate {
    // Call this from your AppDelegate to store the push token
    static func storePushToken(_ deviceToken: Data) {
        let token = deviceToken.map { String(format: "%02.2hhx", $0) }.joined()
        UserDefaults.standard.set(token, forKey: "devicePushToken")
        print("[Push] Device token: \(token)")
    }
}

